INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('461', '<p><strong>56. ฟิสิกส์ : วิทยาศาสตร์ :: .... : ....</strong></p>', '{"A":"ดวงอาทิตย์ : ระบบสุริยะ","B":"เคมี : ห้องทดลอง","C":"วิทยาศาสตร์ประยุกต์ : คณิตศาสตร์","D":"ชีววิทยา : ต้นไม้"}', 'A', '<p><strong>ตอบ 1) ดวงอาทิตย์ : ระบบสุริยะ</strong></p><p>ความสัมพันธ์แบบ "หน่วยเล็ก : หน่วยที่ใหญ่กว่า" หรือ "สาขาวิชาย่อย : วิชาหลัก"</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('462', '<p><strong>57. สายยางรดน้ำ : เชือก :: .... : ....</strong></p>', '{"A":"ท่อไอเสีย : ท่อสูบน้ำ","B":"หลอด : ด้าย","C":"สายบัว : เส้นหมี่","D":"สายป่าน : สายไฟ"}', 'B', '<p><strong>ตอบ 2) หลอด : ด้าย</strong></p><p>ข้อนี้ตอบได้ 2 กรณี ขึ้นอยู่กับดุลยพินิจของผู้ออกข้อสอบ ได้แก่<br/>กรณีที่ 1 ตอบ 2) หลอด : ด้าย<br/>- คำหน้า : สายยางรดน้ำกับหลอด มีลักษณะเป็นท่อกลวงเหมือนกัน<br/>- คำหลัง : เชือกกับด้าย มีลักษณะเป็นเส้นใยถักรวมกันจนทึบเป็นเส้นเหมือนกัน<br/>กรณีที่ 2 ตอบ 4) สายป่าน : สายไฟ<br/>- มีลักษณะนามเหมือนกับโจทย์ คือ เส้น</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('463', '<p><strong>58. เรือนจำ : พัศดี :: .... : ....</strong></p>', '{"A":"นักโทษ : ผู้คุม","B":"โรงพัก : ตำรวจ","C":"โรงเรียน : นักเรียน","D":"หมอ : โรงพยาบาล"}', 'A', '<p><strong>ตอบ 1) นักโทษ : ผู้คุม</strong></p><p>พัศดีมีหน้าที่ดูแลเรือนจำ, ผู้คุมมีหน้าที่ดูแลนักโทษ</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('464', '<p><strong>59. กรอบรูป : ภาพ :: บ้าน : ....</strong></p>', '{"A":"รถ","B":"รั้ว","C":"ห้อง","D":"หน้าต่าง"}', 'C', '<p><strong>ตอบ 3) ห้อง</strong></p><p>ภาพอยู่ภายในกรอบรูป, ห้องอยู่ในบ้าน</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('465', '<p><strong>60. หนังสือพิมพ์ : ข่าว :: สารานุกรม : ....</strong></p>', '{"A":"ความรู้","B":"คำศัพท์","C":"สารบัญ","D":"หนังสือ"}', 'A', '<p><strong>ตอบ 1) ความรู้</strong></p><p>ข่าวอยู่ในหนังสือพิมพ์, ความรู้อยู่ในสารานุกรม</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('466', '<p><strong>61. บุหงา : กำยาน :: น้ำผึ้ง : ....</strong></p>', '{"A":"เกสร","B":"ดอกไม้","C":"ผึ้ง","D":"อ้อย"}', 'D', '<p><strong>ตอบ 4) อ้อย</strong></p><p>บุหงาและกำยาน รับรู้ผ่านจมูก (กลิ่นหอม) เหมือนกัน<br/>น้ำผึ้งและอ้อย รับรู้ผ่านลิ้น (รสหวาน) เหมือนกัน</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('467', '<p><strong>62. ข้าวสาร : ข้าวเปลือก :: ไข่เค็ม : ....</strong></p>', '{"A":"ไข่เป็ด","B":"ไข่เน่า","C":"ไข่แดง","D":"ไข่ตุ๋น"}', 'A', '<p><strong>ตอบ 1) ไข่เป็ด</strong></p><p>ข้าวสารแปรสภาพมาจากข้าวเปลือก, ไข่เค็มแปรสภาพมาจากไข่เป็ด</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('468', '<p><strong>63. น้ำตาล : ตะโก้ :: .... : ....</strong></p>', '{"A":"ใบเตย : กระทง","B":"กะทิ : หม้อแกง","C":"คุกกี้ : แป้ง","D":"องุ่น : ไวน์"}', 'B', '<p><strong>ตอบ 2) กะทิ : หม้อแกง</strong></p><p>ความสัมพันธ์แบบ วัตถุดิบ : ขนม (น้ำตาลเป็นส่วนผสมของตะโก้, กะทิเป็นส่วนผสมของหม้อแกง)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('469', '<p><strong>64. อดีต : อนาคต :: .... : ....</strong></p>', '{"A":"ย่าง : ก้าว","B":"ดำ : มืด","C":"เก่า : ลายคราม","D":"แท้ : เทียม"}', 'D', '<p><strong>ตอบ 4) แท้ : เทียม</strong></p><p>ความสัมพันธ์แบบ คำตรงข้าม</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('470', '<p><strong>65. โรงพยาบาล : คลินิก :: มหาวิทยาลัย : ....</strong></p>', '{"A":"สถาบัน","B":"โรงเรียน","C":"นักศึกษา","D":"อาจารย์"}', 'B', '<p><strong>ตอบ 2) โรงเรียน</strong></p><p>หน้าที่เหมือนกัน (โรงพยาบาลและคลินิกรักษาผู้ป่วย, มหาวิทยาลัยและโรงเรียนให้การศึกษา)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('471', '<p><strong>66. ของที่ระลึก : เหรียญ :: .... : ....</strong></p>', '{"A":"ธนบัตร : พวงกุญแจ","B":"เครื่องเขียน : ดินสอ","C":"กษาปณ์ : ทอง","D":"ไปรษณีย์ : แสตมป์"}', 'B', '<p><strong>ตอบ 2) เครื่องเขียน : ดินสอ</strong></p><p>ความสัมพันธ์แบบ หน่วยใหญ่ : หน่วยเล็ก (เหรียญเป็นสับเซตของของที่ระลึก, ดินสอเป็นสับเซตของเครื่องเขียน)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('472', '<p><strong>67. นม : เนย :: .... : ....</strong></p>', '{"A":"ดีเซล : เบนซิน","B":"น้ำตาล : อ้อย","C":"วุ้นเส้น : ถั่วเขียว","D":"มันสำปะหลัง : เอทานอล"}', 'D', '<p><strong>ตอบ 4) มันสำปะหลัง : เอทานอล</strong></p><p>ความสัมพันธ์แบบ วัตถุดิบ : ผลิตภัณฑ์ (ใช้นมทำเนย, ใช้มันสำปะหลังในการทำเอทานอล)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('473', '<p><strong>68. รูป : กรอบ :: บ้าน : ....</strong></p>', '{"A":"หน้าต่าง","B":"ห้องครัว","C":"คน","D":"รั้ว"}', 'D', '<p><strong>ตอบ 4) รั้ว</strong></p><p>รูปอยู่ในกรอบ, บ้านอยู่ในรั้ว</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('474', '<p><strong>69. หลอด : น้ำ :: ปอด : ....</strong></p>', '{"A":"หัวใจ","B":"เลือด","C":"หายใจ","D":"อากาศ"}', 'D', '<p><strong>ตอบ 4) อากาศ</strong></p><p>ความสัมพันธ์แบบ คำนาม : หน้าที่การใช้งาน (หลอดใช้ดูดน้ำ, ปอดใช้แลกเปลี่ยนอากาศ)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('475', '<p><strong>70. ค้าขาย : กำไร :: ธุรกิจ : ....</strong></p>', '{"A":"หุ้น","B":"คู่ค้า","C":"สินทรัพย์","D":"ผลประกอบการ"}', 'D', '<p><strong>ตอบ 4) ผลประกอบการ</strong></p><p>ความสัมพันธ์แบบ กิจกรรม : ผลลัพธ์ (ค้าขายได้กำไร, ทำธุรกิจได้ผลประกอบการ)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('476', '<p><strong>71. หัตถกรรม : จักรสาน :: เกษตรกรรม : ....</strong></p>', '{"A":"ชาวนา","B":"พืชผล","C":"ประมง","D":"เพาะปลูก"}', 'D', '<p><strong>ตอบ 4) เพาะปลูก</strong></p><p>ความสัมพันธ์แบบ หน่วยใหญ่ : หน่วยเล็ก (การจักรสานเป็นส่วนหนึ่งของหัตถกรรม, การเพาะปลูกเป็นส่วนหนึ่งของเกษตรกรรม โดยมองที่คำกริยาแสดงการลงมือทำ)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["อุปมาอุปไมย"]', '2559');
